// src/Dashboard.js
import React, { useEffect, useState } from "react";
import axios from "axios";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import "leaflet/dist/leaflet.css";

export default function Dashboard() {
  const [alerts, setAlerts] = useState([]);
  const token = localStorage.getItem("token");
  const user = JSON.parse(localStorage.getItem("user"));

  // Fetch Alerts
  const fetchAlerts = async () => {
    try {
      const res = await axios.get(
        "http://localhost:5000/api/alerts",
        {
          headers: { Authorization: `Bearer ${token}` },
        }
      );
      setAlerts(res.data);
    } catch (error) {
      console.error(error);
    }
  };

  useEffect(() => {
    fetchAlerts();
  }, []);

  // SOS Button
  const sendSOS = () => {
    navigator.geolocation.getCurrentPosition(async (pos) => {
      try {
        await axios.post(
          "http://localhost:5000/api/alerts",
          {
            latitude: pos.coords.latitude,
            longitude: pos.coords.longitude,
          },
          {
            headers: { Authorization: `Bearer ${token}` },
          }
        );
        alert("SOS Sent 🚨");
        fetchAlerts();
      } catch (error) {
        console.error(error);
      }
    });
  };

  // Accept Alert (Volunteer)
  const acceptAlert = async (id) => {
    await axios.put(
      `http://localhost:5000/api/alerts/accept/${id}`,
      {},
      {
        headers: { Authorization: `Bearer ${token}` },
      }
    );
    fetchAlerts();
  };

  // Resolve Alert
  const resolveAlert = async (id) => {
    await axios.put(
      `http://localhost:5000/api/alerts/resolve/${id}`,
      {},
      {
        headers: { Authorization: `Bearer ${token}` },
      }
    );
    fetchAlerts();
  };

  return (
    <div style={{ textAlign: "center", padding: "20px" }}>
      <h1>Welcome, {user?.name}</h1>

      {/* SOS Button */}
      {user?.role === "user" && (
        <button
          onClick={sendSOS}
          style={{
            padding: "15px",
            fontSize: "18px",
            backgroundColor: "red",
            color: "white",
            border: "none",
            borderRadius: "10px",
            marginBottom: "20px",
          }}
        >
          🚨 SOS
        </button>
      )}

      <h2>Emergency Alerts</h2>

      {/* Alerts List */}
      {alerts.map((alert) => (
        <div
          key={alert._id}
          style={{
            border: "1px solid #ccc",
            padding: "10px",
            margin: "10px",
          }}
        >
          <p><strong>User:</strong> {alert.userEmail}</p>
          <p><strong>Status:</strong> {alert.status}</p>
          <p>
            <strong>Location:</strong> {alert.latitude}, {alert.longitude}
          </p>

          {/* Volunteer/Admin Actions */}
          {(user?.role === "volunteer" ||
            user?.role === "admin") && (
            <>
              {alert.status === "pending" && (
                <button onClick={() => acceptAlert(alert._id)}>
                  Accept
                </button>
              )}
              {alert.status === "accepted" && (
                <button onClick={() => resolveAlert(alert._id)}>
                  Resolve
                </button>
              )}
            </>
          )}
        </div>
      ))}

      {/* Live Map */}
      <h2>Live Map</h2>
      <MapContainer
        center={[20.5937, 78.9629]}
        zoom={5}
        style={{ height: "400px", width: "80%", margin: "auto" }}
      >
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
        {alerts.map((alert) => (
          <Marker
            key={alert._id}
            position={[alert.latitude, alert.longitude]}
          >
            <Popup>
              {alert.userEmail} <br />
              Status: {alert.status}
            </Popup>
          </Marker>
        ))}
      </MapContainer>
    </div>
  );
}
